+            reason: "ok".to_string(),
+            witness: "w".to_string(),
+            line: 0,
+        });
+
+        let auditor = SourceAuditor::new(AuditConfig::standard(), exemptions);
+        let mut sources = BTreeMap::new();
+        // m1: exempted filesystem use
+        sources.insert(
+            ("m1".to_string(), "f1.rs".to_string()),
+            "let _ = std::fs::read(\"x\");".to_string(),
+        );
+        // m2: unexempted network use
