+extract_json_report() {
+  local source_path="$1"
+  local destination_path="$2"
+
+  awk '
+    function strip_strings(line,    ch, i, in_string, escaped, result) {
+      result = ""
+      in_string = 0
+      escaped = 0
+      for (i = 1; i <= length(line); i++) {
+        ch = substr(line, i, 1)
+        if (in_string) {
+          if (escaped) {
+            escaped = 0
+            continue
+          }
+          if (ch == "\\") {
+            escaped = 1
+            continue
+          }
+          if (ch == "\"") {
+            in_string = 0
+          }
+          continue
+        }
+        if (ch == "\"") {
+          in_string = 1
+          continue
+        }
+        result = result ch
+      }
+      return result
+    }
+
+    BEGIN {
+      capture = 0
+      depth = 0
+    }
+
+    {
+      line = $0
+      if (!capture) {
+        if (line ~ /^[[:space:]]*\{[[:space:]]*$/) {
+          capture = 1
+        } else {
+          next
+        }
+      }
+
+      if (capture) {
+        print line
+        stripped = strip_strings(line)
+        opens = gsub(/\{/, "&", stripped)
+        closes = gsub(/\}/, "&", stripped)
+        depth += opens - closes
+        if (depth == 0) {
+          exit
+        }
+      }
+    }
+  ' "$source_path" >"$destination_path"
+}
